function getBDTimestamp() {
  const now = new Date();
  const bd = new Date(now.getTime() + (6 * 60 * 60 * 1000));
  const h = bd.getUTCHours();
  const ampm = h >= 12 ? 'PM' : 'AM';
  const h12 = h % 12 || 12;
  return String(bd.getUTCDate()).padStart(2,'0') + '-' +
         String(bd.getUTCMonth()+1).padStart(2,'0') + '-' +
         bd.getUTCFullYear() + ' ' +
         h12 + ':' + String(bd.getUTCMinutes()).padStart(2,'0') + ':' +
         String(bd.getUTCSeconds()).padStart(2,'0') + ' ' + ampm;
}
const ts = getBDTimestamp();

const allItems = $input.all();
if (!allItems || allItems.length === 0) {
  return [{ json: { "AI Reply": "Sorry, I couldn't get a response right now. Please try again.", "AI Reply Sheet": "Sorry, I couldn't get a response right now. Please try again.", "Intent": "inquiry", "Status": "error", "Order Data": "", "User Message": "", "Session ID": "", "Timestamp": ts } }];
}

try {
  const upstreamError = $input.first().json.error;
  if (upstreamError) {
    const msg = typeof upstreamError === 'object' ? (upstreamError.message || JSON.stringify(upstreamError)) : String(upstreamError);
    return [{ json: { "AI Reply": "Sorry, the AI service is temporarily unavailable. Please try again.", "AI Reply Sheet": "Sorry, the AI service is temporarily unavailable. Please try again.", "Intent": "inquiry", "Status": "error", "Order Data": "", "User Message": "", "Session ID": "", "Timestamp": ts, "error": msg } }];
  }

  const aiChoices = $input.first().json.choices;
  if (!aiChoices || !aiChoices[0] || !aiChoices[0].message) {
    return [{ json: { "AI Reply": "Sorry, I'm having a temporary issue. Please try again.", "AI Reply Sheet": "Sorry, I'm having a temporary issue. Please try again.", "Intent": "inquiry", "Status": "error", "Order Data": "", "User Message": "", "Session ID": "", "Timestamp": ts, "error": "No AI response" } }];
  }

  const aiText = aiChoices[0].message.content || "";
  const buildNode = $('Build Messages');
  const userMessage = buildNode.first().json.userMessage || "";
  const sessionId = buildNode.first().json.sessionId || "";

  // Update session history
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.sessions) staticData.sessions = {};
  if (!staticData.sessions[sessionId]) staticData.sessions[sessionId] = [];
  staticData.sessions[sessionId].push({ role: "assistant", content: aiText });
  if (staticData.sessions[sessionId].length > 24) {
    staticData.sessions[sessionId].splice(0, staticData.sessions[sessionId].length - 24);
  }

  // Extract [INTENT: ...] tag
  const intentMatch = aiText.match(/\[INTENT:\s*(booking|order|inquiry|cancel)\]/i);
  const intent = intentMatch ? intentMatch[1].toLowerCase().trim() : "inquiry";

  // Extract [[DATA_START]]...[[DATA_END]] block
  const dataBlockMatch = aiText.match(/\[\[DATA_START\]\]([\s\S]*?)\[\[DATA_END\]\]/i);
  const dataBlock = dataBlockMatch ? dataBlockMatch[1].trim() : "";

  // Determine status — now using specific cancel type tags
  let status = "pending";
  let cancelType = "";
  if (/ORDER_CONFIRMED/i.test(dataBlock))    status = "confirmed";
  else if (/SESSION_CONFIRMED/i.test(dataBlock)) status = "confirmed";
  else if (/CANCELLED_ORDER/i.test(dataBlock))  { status = "cancelled"; cancelType = "order"; }
  else if (/CANCELLED_BOOKING/i.test(dataBlock)){ status = "cancelled"; cancelType = "booking"; }

  // Parse fields from DATA block
  const getField = (block, key) => {
    const m = block.match(new RegExp(String(key) + ':\\s*([^\\n]+)', 'i'));
    return m ? m[1].trim() : "";
  };
  const f = {
    product:  getField(dataBlock, 'Product'),
    quantity: getField(dataBlock, 'Quantity'),
    name:     getField(dataBlock, 'Name'),
    phone:    getField(dataBlock, 'Phone'),
    email:    getField(dataBlock, 'Email'),
    address:  getField(dataBlock, 'Address'),
    total:    getField(dataBlock, 'Total'),
    date:     getField(dataBlock, 'Date'),
    time:     getField(dataBlock, 'Time'),
    platform: getField(dataBlock, 'Platform'),
    reason:   getField(dataBlock, 'Reason'),
  };

  // Build Order Data string — multiline format for easy reading in Google Sheets
  let orderData = "";
  if (status === "confirmed" && intent === "order") {
    orderData = [
      "Order Confirmed",
      "Product: "  + (f.product  || "N/A"),
      "Qty: "      + (f.quantity || "1"),
      "Name: "     + (f.name     || "N/A"),
      "Phone: "    + (f.phone    || "N/A"),
      "Email: "    + (f.email    || "N/A"),
      "Address: "  + (f.address  || "N/A"),
      "Total: "    + (f.total    || "N/A")
    ].join("\n");
  } else if (status === "confirmed" && intent === "booking") {
    orderData = [
      "Booking Confirmed",
      "Name: "     + (f.name     || "N/A"),
      "Email: "    + (f.email    || "N/A"),
      "Date: "     + (f.date     || "N/A"),
      "Time: "     + (f.time     || "N/A"),
      "Platform: " + (f.platform || "N/A"),
      "Reason: "   + (f.reason   || "General inquiry")
    ].join("\n");
  } else if (status === "cancelled" && cancelType === "order") {
    orderData = [
      "Order Cancelled",
      "Product: "  + (f.product  || "N/A"),
      "Qty: "      + (f.quantity || "N/A"),
      "Name: "     + (f.name     || "N/A"),
      "Phone: "    + (f.phone    || "N/A"),
      "Email: "    + (f.email    || "N/A"),
      "Address: "  + (f.address  || "N/A"),
      "Total: "    + (f.total    || "N/A"),
      "Reason: "   + (f.reason   || "No reason specified")
    ].join("\n");
  } else if (status === "cancelled" && cancelType === "booking") {
    orderData = [
      "Booking Cancelled",
      "Name: "     + (f.name     || "N/A"),
      "Email: "    + (f.email    || "N/A"),
      "Date: "     + (f.date     || "N/A"),
      "Time: "     + (f.time     || "N/A"),
      "Platform: " + (f.platform || "N/A"),
      "Reason: "   + (f.reason   || "No reason specified")
    ].join("\n");
  }

  // Strip technical blocks from reply
  const stripTechnical = (text) => text
    .replace(/\[\[DATA_START\]\][\s\S]*?\[\[DATA_END\]\]/gi, "")
    .replace(/\[INTENT:\s*\w+\]/gi, "")
    .replace(/^[━=\-_]{3,}\s*$/gm, "")
    .replace(/```[\s\S]*?```/g, "")
    .replace(/^#{1,6}\s/gm, "")
    .replace(/—/g, "")
    .replace(/^[-•*]\s+/gm, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  // Frontend reply: keep **bold** for markdownToHtml rendering
  let replyFrontend = stripTechnical(aiText);
  if (!replyFrontend || replyFrontend.length < 5) {
    replyFrontend = "I'm here to help! What can I find for you today?";
  }

  // Sheets reply: strip all markdown to plain readable text
  let replySheet = stripTechnical(aiText)
    .replace(/\*\*([^*]+?)\*\*/g, "$1")
    .replace(/\*([^*]+?)\*/g, "$1")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  if (!replySheet || replySheet.length < 5) {
    replySheet = "I'm here to help! What can I find for you today?";
  }

  return [{
    json: {
      "AI Reply":       replyFrontend,
      "AI Reply Sheet": replySheet,
      "Intent":         intent,
      "Status":         status,
      "Cancel Type":    cancelType,
      "Order Data":     orderData,
      "User Message":   userMessage,
      "Session ID":     sessionId,
      "Timestamp":      ts
    }
  }];

} catch (err) {
  return [{
    json: {
      "AI Reply":       "Sorry, I'm having a temporary issue. Please try again.",
      "AI Reply Sheet": "Sorry, I'm having a temporary issue. Please try again.",
      "Intent":         "inquiry",
      "Status":         "error",
      "Cancel Type":    "",
      "Order Data":     "",
      "User Message":   "",
      "Session ID":     "",
      "Timestamp":      getBDTimestamp(),
      "error":          err.message
    }
  }];
}

// Precisely delete the correct Sheet2 row when customer cancels.
// Reads from Parse & Clean Output (not Action Route) to get all fields.
// Uses multiple matching strategies to identify the right row.

const currentJson     = $('Parse & Clean Output').first().json;
const sessionId       = (currentJson['Session ID']  || '').trim();
const cancelType      = (currentJson['Cancel Type'] || '').trim().toLowerCase();
const cancelOrderData = (currentJson['Order Data']  || '');
const aiReply         = (currentJson['AI Reply']    || '');

if (!sessionId || !cancelType) return [];

// ── Extract cancelled product name from multiple sources ──────────────
// Source 1: Order Data field built from the DATA block (most reliable)
const prodFromData = (() => {
  const m = cancelOrderData.match(/Product:\s*([^\n]+)/i);
  return m ? m[1].trim().toLowerCase() : '';
})();

// Source 2: Visible AI reply — look for product name in cancellation summary
const prodFromReply = (() => {
  const m = aiReply.match(/Product:\s*([^\n<]+)/i);
  return m ? m[1].replace(/<[^>]*>/g, '').trim().toLowerCase() : '';
})();

// Source 3: Total amount from Order Data (unique per product — reliable fallback)
const totalFromData = (() => {
  const m = cancelOrderData.match(/Total:\s*([^\n]+)/i);
  return m ? m[1].trim().toLowerCase() : '';
})();

// Use the most specific product name available
const cancelledProduct = prodFromData || prodFromReply;

// ── Row matching function ──────────────────────────────────────────────
// A row matches the cancelled product if:
// - cancelledProduct is a substring of the row's product name (or vice versa)
// - OR the total amounts match (fallback when names differ slightly)
const rowMatchesCancel = (rowData) => {
  const rLow = rowData.toLowerCase();

  // Extract product name and total from the sheet row
  const rowProdMatch = rLow.match(/product:\s*([^\n]+)/);
  const rowProd = rowProdMatch ? rowProdMatch[1].trim() : '';

  const rowTotalMatch = rLow.match(/total:\s*([^\n]+)/);
  const rowTotal = rowTotalMatch ? rowTotalMatch[1].trim() : '';

  if (cancelledProduct) {
    // Bidirectional substring check:
    // Does the row's product contain the cancelled name? (e.g. row='Corsair K70 Keyboard', cancel='Corsair K70')
    // Does the cancelled name contain the row's product? (e.g. cancel='Corsair K70 keyboard', row='Corsair K70')
    const nameMatch = rowProd.includes(cancelledProduct) || cancelledProduct.includes(rowProd);
    if (nameMatch && rowProd.length > 0) return true;

    // Fallback: if name match fails but total matches, use that
    if (totalFromData && rowTotal && rowTotal === totalFromData.toLowerCase()) return true;
  } else {
    // No product name at all — use total as sole identifier
    if (totalFromData && rowTotal && rowTotal === totalFromData.toLowerCase()) return true;
  }

  return false;
};

const allRows = $input.all();

const rowsToDelete = allRows
  .filter(row => {
    const rowSession = (row.json['Session ID'] || '').toString().trim();
    const rowIntent  = (row.json['Intent']     || '').toString().trim().toLowerCase();
    const rowStatus  = (row.json['Status']     || '').toString().trim().toLowerCase();
    const rowData    = (row.json['Order Data'] || '').toString();

    if (rowSession !== sessionId)   return false;
    if (rowStatus  !== 'confirmed') return false;

    if (cancelType === 'order') {
      if (rowIntent !== 'order') return false;
      return rowMatchesCancel(rowData);
    }

    if (cancelType === 'booking') {
      if (rowIntent !== 'booking') return false;
      return true;  // One booking per session — always matches
    }

    return false;
  })
  .map(row => {
    const n = row.json['row_number'] || row.json['rowNumber'] || row.json['_rowNumber'];
    return { json: { row_number: Number(n) } };
  })
  .filter(item => item.json.row_number && !isNaN(item.json.row_number))
  .sort((a, b) => b.json.row_number - a.json.row_number);

return rowsToDelete.length > 0 ? rowsToDelete : [];

// Dedup: when a new confirmation is written to Sheet2, delete the OLD row
// for that SAME order/booking if it already exists (discount / detail update).
// NEVER delete a different product's row or a booking when an order changes.

const currentJson  = $('Parse & Clean Output').first().json;
const sessionId    = (currentJson['Session ID'] || '').trim();
const intent       = (currentJson['Intent']     || '').trim().toLowerCase();
const currentData  = (currentJson['Order Data'] || '').trim();

if (!sessionId || !currentData) {
  return [];
}

// For ORDERS  : the unique key is the Product name.
//   Same product re-confirmed (e.g. after discount or qty change) → replace.
//   Different product → keep both rows.
// For BOOKINGS: the unique key is the Session ID itself.
//   A session has only ONE booking. Any re-confirmation (new date/time/platform)
//   replaces the previous booking row regardless of what changed.
const getKey = (data, intentType) => {
  if (intentType === 'order') {
    const m = data.match(/Product:\s*([^\n]+)/i);
    return m ? m[1].trim().toLowerCase() : '';
  }
  if (intentType === 'booking') {
    // All bookings in a session share the same session key
    return 'booking';
  }
  return '';
};

const currentKey = getKey(currentData, intent);
if (!currentKey) return [];

const allRows = $input.all();

const rowsToDelete = allRows
  .filter(row => {
    const rowSession = (row.json['Session ID'] || '').toString().trim();
    const rowIntent  = (row.json['Intent']     || '').toString().trim().toLowerCase();
    const rowStatus  = (row.json['Status']     || '').toString().trim().toLowerCase();
    const rowData    = (row.json['Order Data'] || '').toString().trim();

    if (rowSession !== sessionId)   return false;  // different session
    if (rowIntent  !== intent)      return false;  // different type (order vs booking)
    if (rowStatus  !== 'confirmed') return false;  // only remove confirmed rows
    if (rowData    === currentData) return false;  // this IS the newly written row

    // For orders: only remove if the row is the same product
    const rowKey = getKey(rowData, rowIntent);
    return rowKey !== '' && rowKey === currentKey;
  })
  .map(row => {
    const n = row.json['row_number'] || row.json['rowNumber'] || row.json['_rowNumber'];
    return { json: { row_number: Number(n) } };
  })
  .filter(item => item.json.row_number && !isNaN(item.json.row_number))
  .sort((a, b) => b.json.row_number - a.json.row_number);

return rowsToDelete.length > 0 ? rowsToDelete : [];
